from enum import Enum

class TaskComplexity(Enum):
    SIMPLE = "simple"      # factual lookup, short summarisation
    MODERATE = "moderate"  # multi-step explanation, small code function
    COMPLEX = "complex"    # algorithm design, multi-constraint reasoning
    EXPERT = "expert"      # formal proof, architecture critique, adversarial analysis

THINKING_BUDGETS = {
    TaskComplexity.SIMPLE:   1024,
    TaskComplexity.MODERATE: 4000,
    TaskComplexity.COMPLEX:  10000,
    TaskComplexity.EXPERT:   32000,
}

def classify_task(prompt: str) -> TaskComplexity:
    """Lightweight heuristic — replace with a small routing LLM call for production."""
    p = prompt.lower()
    if any(w in p for w in ["prove", "formal", "adversarial", "security audit"]):
        return TaskComplexity.EXPERT
    if any(w in p for w in ["design", "architecture", "algorithm", "optimize"]):
        return TaskComplexity.COMPLEX
    if any(w in p for w in ["explain", "implement", "write a function"]):
        return TaskComplexity.MODERATE
    return TaskComplexity.SIMPLE

def adaptive_call(prompt: str) -> str:
    complexity = classify_task(prompt)
    budget = THINKING_BUDGETS[complexity]
    response = client.messages.create(
        model="claude-sonnet-4-6",
        max_tokens=budget + 4096,
        thinking={"type": "enabled", "budget_tokens": budget},
        messages=[{"role": "user", "content": prompt}],
    )
    return next(b.text for b in response.content if b.type == "text")

def debug_wrong_answer(prompt: str, expected_answer: str) -> dict:
    response = client.messages.create(
        model="claude-sonnet-4-6",
        max_tokens=16000,
        thinking={"type": "enabled", "budget_tokens": 10000},
        messages=[{"role": "user", "content": prompt}],
    )

    thinking_text = ""
    actual_answer = ""
    for block in response.content:
        if block.type == "thinking":
            thinking_text = block.thinking
        elif block.type == "text":
            actual_answer = block.text

    is_correct = expected_answer.strip().lower() in actual_answer.lower()

    if not is_correct:
        # Look for the failure point in the thinking chain
        lines = thinking_text.split("\n")
        suspicious = [l for l in lines if any(kw in l.lower()
                      for kw in ["assume", "therefore", "so ", "this means"])]
        return {
            "correct": False,
            "answer": actual_answer,
            "key_reasoning_steps": suspicious[:10],
            "full_thinking": thinking_text,
        }

    return {"correct": True, "answer": actual_answer}

